cd d:\Developing\jsbeat; node -e "const fs = require('fs'); const path = require('path'); const songsDir = './songs'; const dirs = fs.readdirSync(songsDir).filter(f => fs.statSync(path.join(songsDir, f)).isDirectory() && !f.startsWith('.')); console.log('Found ' + dirs.length + ' song directories'); const songs = []; dirs.forEach(dir => { const manifestPath = path.join(songsDir, dir, 'manifest.txt'); if (fs.existsSync(manifestPath)) { const content = fs.readFileSync(manifestPath, 'utf8'); const lines = content.split('\n'); let name = '', artist = '', bpm = '', levels = []; lines.forEach(line => { line = line.trim(); if (line.startsWith('Name=')) name = line.substring(5); else if (line.startsWith('Composer=')) artist = line.substring(9); else if (line.startsWith('BPM=')) bpm = parseInt(line.substring(4)); else if (line.startsWith('Level=')) levels = line.substring(6).split(',').map(l => parseInt(l.trim())); }); if (name) { songs.push({ id: dir, name, artist, bpm, levels }); } } }); console.log('Processed ' + songs.length + ' songs with valid manifests'); fs.writeFileSync(path.join(songsDir, 'songs.json'), JSON.stringify({ songs }, null, 2), 'utf8'); console.log('songs.json updated successfully');"